import React from "react";

function IndividualAnalysis({ customerData, onInputChange, onAnalyze, loading, results }) {
  const handleChange = (e) => {
    const { name, value } = e.target;
    onInputChange({ ...customerData, [name]: value });
  };

  return (
    <div className="grid-wrapper">
      {/* 💰 Core Metrics */}
      <div className="grid-card">
        <h3>💰 Core Metrics</h3>

        <label>Tenure<input type="number" name="Tenure" value={customerData.Tenure} onChange={handleChange} /></label>
        <label>Order Count<input type="number" name="OrderCount" value={customerData.OrderCount} onChange={handleChange} /></label>
        <label>Cashback Amount<input type="number" name="CashbackAmount" value={customerData.CashbackAmount} onChange={handleChange} /></label>
        <label>Order Hike %<input type="number" name="OrderAmountHikeFromlastYear" value={customerData.OrderAmountHikeFromlastYear} onChange={handleChange} /></label>
        <label>Coupon Used<input type="number" name="CouponUsed" value={customerData.CouponUsed} onChange={handleChange} /></label>
        <label>Number Of Devices<input type="number" name="NumberOfDeviceRegistered" value={customerData.NumberOfDeviceRegistered} onChange={handleChange} /></label>
        <label>Satisfaction Score<input type="number" name="SatisfactionScore" value={customerData.SatisfactionScore} onChange={handleChange} /></label>
      </div>

      {/* 🛠️ Service & Logistics */}
      <div className="grid-card">
        <h3>🛠️ Service & Logistics</h3>

        <label>Day Since Last Order<input type="number" name="DaySinceLastOrder" value={customerData.DaySinceLastOrder} onChange={handleChange} /></label>
        <label>Hours On App<input type="number" name="HourSpendOnApp" value={customerData.HourSpendOnApp} onChange={handleChange} /></label>
        <label>Warehouse Distance<input type="number" name="WarehouseToHome" value={customerData.WarehouseToHome} onChange={handleChange} /></label>
        <label>Number Of Addresses<input type="number" name="NumberOfAddress" value={customerData.NumberOfAddress} onChange={handleChange} /></label>
        <label>Complaint<select name="Complain" value={customerData.Complain} onChange={handleChange}><option value={0}>No</option><option value={1}>Yes</option></select></label>
        <label>Preferred Login Device<select name="PreferredLoginDevice" value={customerData.PreferredLoginDevice} onChange={handleChange}><option>Mobile Phone</option><option>Computer</option><option>Tablet</option></select></label>
        <label>Preferred Order Category<select name="PreferedOrderCat" value={customerData.PreferedOrderCat} onChange={handleChange}><option>Laptop & Accessory</option><option>Mobile & Accessory</option><option>Grocery</option><option>Fashion</option></select></label>
      </div>

      {/* 🧑‍ Demographics */}
      <div className="grid-card">
        <h3>🧑‍ Demographics</h3>

        <label>Gender<select name="Gender" value={customerData.Gender} onChange={handleChange}><option>Male</option><option>Female</option><option>Other</option></select></label>
        <label>Marital Status<select name="MaritalStatus" value={customerData.MaritalStatus} onChange={handleChange}><option>Married</option><option>Single</option></select></label>
        <label>City Tier<input type="number" name="CityTier" value={customerData.CityTier} onChange={handleChange} /></label>
        <label>Preferred Payment Mode<select name="PreferredPaymentMode" value={customerData.PreferredPaymentMode} onChange={handleChange}><option>Credit Card</option><option>Debit Card</option><option>UPI</option><option>Net Banking</option></select></label>
      </div>

      {/* Analyze Button */}
      <button className="analyze-btn" onClick={onAnalyze} disabled={loading}>
        {loading ? "Analyzing..." : "🚀 Run Prediction"}
      </button>

      {results && (
        <div className="results-card">
          <h3>📊 Prediction Results</h3>
          <pre>{JSON.stringify(results, null, 2)}</pre>
        </div>
      )}
    </div>
  );
}

export default IndividualAnalysis;
